import pytest

from models import EmailMatch

# ---------------------------------------------------------------------------
# Update after first run against your test statement PDF
# ---------------------------------------------------------------------------
EXPECTED_MIN_EMAIL_COUNT = None     # e.g. 5 — lower bound on emails with attachments
EXPECTED_SENDER_DOMAIN = None       # e.g. "amazonaws.com" — a known sender domain
# ---------------------------------------------------------------------------


def test_fetch_emails_returns_results(real_emails):
    assert len(real_emails) > 0


def test_fetch_emails_all_have_required_fields(real_emails):
    for email in real_emails:
        assert isinstance(email, EmailMatch)
        assert email.email_id
        assert email.date
        assert isinstance(email.attachment_filenames, list)


def test_fetch_emails_all_have_attachments(real_emails):
    for email in real_emails:
        assert len(email.attachment_filenames) > 0, (
            f"Email {email.email_id} has no attachments — should have been filtered by Gmail query"
        )


def test_fetch_emails_minimum_count(real_emails):
    if EXPECTED_MIN_EMAIL_COUNT is None:
        pytest.skip("EXPECTED_MIN_EMAIL_COUNT not set")
    assert len(real_emails) >= EXPECTED_MIN_EMAIL_COUNT


def test_fetch_emails_known_sender_present(real_emails):
    if EXPECTED_SENDER_DOMAIN is None:
        pytest.skip("EXPECTED_SENDER_DOMAIN not set")
    senders = [e.sender for e in real_emails]
    assert any(EXPECTED_SENDER_DOMAIN in s for s in senders), (
        f"No email from {EXPECTED_SENDER_DOMAIN!r} found"
    )

