    results, _, _ = real_pipeline_results
    for r in results:
        if r.status == "found":
            assert r.email_id is not None
            assert r.attachment_path is not None


def test_match_missing_have_failure_reason(real_pipeline_results):
    results, _, _ = real_pipeline_results
    for r in results:
        if r.status == "missing":
            assert r.failure_reason is not None


