    if EXPECTED_FOUND_COUNT is None:
        pytest.skip("EXPECTED_FOUND_COUNT not set")
    results, _, _ = real_pipeline_results
    found = [r for r in results if r.status == "found"]
    assert len(found) == EXPECTED_FOUND_COUNT


