    if EXPECTED_MISSING_COUNT is None:
        pytest.skip("EXPECTED_MISSING_COUNT not set")
    results, _, _ = real_pipeline_results
    missing = [r for r in results if r.status == "missing"]
    assert len(missing) == EXPECTED_MISSING_COUNT


def test_match_known_vendor_found(real_pipeline_results):
    if EXPECTED_FOUND_VENDOR is None:
        pytest.skip("EXPECTED_FOUND_VENDOR not set")
    results, _, _ = real_pipeline_results
    found_vendors = {r.transaction.vendor for r in results if r.status == "found"}
    assert EXPECTED_FOUND_VENDOR in found_vendors, (
        f"{EXPECTED_FOUND_VENDOR!r} expected to be found but wasn't"
    )


